 "use client";

 import { useDialKit } from "dialkit";
 import { useTheme } from "next-themes";

 import { ThemeToggle } from "@/registry/new-york/theme-toggle";
 import type { TransitionVariant } from "@/registry/new-york/theme-toggle";

 const config = {
   duration: [200, 100, 1000] as [number, number, number],
   fromCenter: false,
   variant: {
     default: "circle",
     options: [
       "circle",
       "square",
       "triangle",
       "diamond",
       "hexagon",
       "rectangle",
       "star",
     ],
-    type: "select",
+    type: "select" as const,
   },
 };

 export const ThemeToggleDemo = () => {
   const values = useDialKit("theme-toggle", config);
   const { resolvedTheme, setTheme } = useTheme();

   return (
     <div className="flex flex-col items-center gap-8">
       <ThemeToggle
         variant={values.variant as TransitionVariant}
         fromCenter={values.fromCenter as boolean}
         duration={values.duration as number}
         theme={resolvedTheme === "dark" ? "light" : "dark"}
         onThemeChange={setTheme}
         className="inline-flex h-10 w-10 items-center justify-center rounded-full border border-border bg-card text-foreground"
       />
     </div>
   );
 };

parts.text:
The issue is that the `config` object in `theme-toggle-demo.tsx` has properties that don't match the `DialConfig` type. The `DialConfig` type is:

```typescript
type DialConfig = {
    [key: string]: DialValue | [number, number, number, number?] | DialConfig;
};
```

Where `DialValue = number | boolean | string | SpringConfig | EasingConfig | ActionConfig | SelectConfig | ColorConfig | TextConfig`.

The `variant` property in the config has `{ default: string; options: string[]; type: string; }`. But `SelectConfig` expects `type: 'select'` (a string literal), not `type: string`.

The issue is that `type: "select"` is being inferred as `type: string` instead of the literal `"select"`. This is because TypeScript widens the type when the object is defined without `as const`.

The fix is to add `as const` to the config object, or to explicitly type the `variant` property.

Let me read the actual config to confirm.

